export const BLOG_POST_BY_SLUG = BLOG_POSTS.reduce((acc, post) => {
    acc[post.slug] = post;
    return acc;
}, {});

export function getBlogUrl(post) {
    return `/blog/${post.slug}`;
}

export function getCanonicalUrl(post) {
    return `${SITE.origin}${getBlogUrl(post)}`;
}

export function getAbsoluteImageUrl(post) {
    if (!post?.image?.src) return SITE.defaultImage;
    if (/^https?:\/\//i.test(post.image.src)) return post.image.src;
    return `${SITE.origin}${post.image.src}`;
}

export function getAllKeywords(post) {
    return [post.focusKeyword, ...(post.secondaryKeywords || [])].filter(Boolean);
}
